import supertest from 'supertest';
import app from '@app'; // Alias import
import logger from '@utils/logger'; // Spy on logger

jest.spyOn(logger, 'info'); // Spy on logger.info
jest.spyOn(logger, 'error'); // Spy on logger.error

describe('App Entrypoint', () => {
  beforeEach(() => {
    jest.clearAllMocks();
  });

  it('should handle /api/user/profile route', async () => {
    const response = await supertest(app).get('/api/user/profile');
    expect(response.status).toBe(200);
    expect(response.body).toEqual({ success: true });
    expect(logger.info).toHaveBeenCalled();
  });

  it('should handle /api/auctions route', async () => {
    const response = await supertest(app).get('/api/auctions');
    expect(response.status).toBe(200);
    expect(response.body).toEqual({ success: true });
    expect(logger.info).toHaveBeenCalled();
  });

  it('should include correlation ID in error logs', async () => {
    const response = await supertest(app)
      .get('/api/nonexistent')
      .set('x-correlation-id', 'test-corr');
    expect(response.status).toBe(500);
    expect(logger.error).toHaveBeenCalledWith(expect.any(String), expect.objectContaining({ correlationId: 'test-corr' }));
  });
});
